INSERT INTO t_p28138419_nova_initiative_14.engineering_articles
(slug, h1, seo_title, seo_description, seo_keywords, summary, quick_facts, body_html, bibliography, author_name, author_role, cover_url, reading_minutes, is_published)
VALUES (
'raschet-tsilindricheskoy-zubchatoy-peredachi-vkr',
'Расчёт цилиндрической зубчатой передачи в дипломе: контактная и изгибная выносливость по ГОСТ 21354-87',
'Расчёт зубчатой передачи редуктора в ВКР — модуль, контактные и изгибные напряжения · Диплом-Инж.рф',
'Полный алгоритм проектного и проверочного расчёта цилиндрической зубчатой передачи для дипломного проекта: выбор материала и термообработки, межосевое расстояние, модуль, проверка по контактной и изгибной выносливости по ГОСТ 21354-87, проверка в КОМПАС APM FEM.',
'расчёт зубчатой передачи, цилиндрическая передача, модуль зацепления, контактные напряжения, изгибная выносливость, ГОСТ 21354-87, межосевое расстояние, редуктор чертёж ВКР, число зубьев, коэффициент ширины венца, КОМПАС APM, расчёт редуктора диплом',
'Цилиндрическая зубчатая передача — сердце редуктора и обязательный раздел дипломного проекта по машиностроению. Разбираем сквозной алгоритм: от выбора стали и термообработки до проверки зуба по контактной и изгибной выносливости по ГОСТ 21354-87 и конечно-элементной верификации в отечественной САПР.',
'[
  {"q":"Как выбрать допускаемые контактные напряжения для колеса?","a":"Допускаемое контактное напряжение [σ_H] = σ_H lim b · K_HL / S_H, где σ_H lim b — предел контактной выносливости при базовом числе циклов (для улучшенных сталей σ_H lim b = 2·HB + 70 МПа), K_HL — коэффициент долговечности, S_H = 1,1 — коэффициент запаса по контактным напряжениям. Расчёт ведут по менее прочному из колёс пары — обычно по колесу [1, с. 33; 5, с. 51]."},
  {"q":"По какой формуле определяют межосевое расстояние?","a":"Проектное межосевое расстояние косозубой передачи: a_w = K_a·(u+1)·∛(T_2·K_Hβ / (ψ_ba·u²·[σ_H]²)), где K_a = 43 для косозубых и 49,5 для прямозубых передач, u — передаточное число, T_2 — момент на колесе в Н·мм, ψ_ba — коэффициент ширины венца, K_Hβ — коэффициент концентрации нагрузки. Результат округляют до стандартного по ГОСТ 2185-66 [3, с. 36; 1, с. 32]."},
  {"q":"Как назначается модуль зацепления?","a":"Модуль m = (0,01…0,02)·a_w, затем округляется до стандартного значения по ГОСТ 9563-60 (ряд 1; 1,25; 1,5; 2; 2,5; 3; 4; 5…). Модуль менее 1,5 мм для силовых передач редукторов не назначают из условия изгибной прочности зуба и технологичности нарезания [3, с. 38]."},
  {"q":"Что проверяют при расчёте на изгибную выносливость?","a":"Проверяют напряжение у основания зуба: σ_F = (F_t·K_F·Y_F·Y_β / (b·m)) ≤ [σ_F], где Y_F — коэффициент формы зуба (зависит от числа зубьев), Y_β — коэффициент наклона зуба, [σ_F] = σ_F lim b·K_FL / S_F — допускаемое изгибное напряжение, S_F = 1,7…2,2. Изгиб — критерий поломки зуба, контакт — критерий выкрашивания рабочих поверхностей [1, с. 44; 5, с. 58]."},
  {"q":"Зачем считать передачу в КЭ-системе, если есть ГОСТ 21354-87?","a":"ГОСТ-методика даёт интегральную оценку и закладывает запасы по справочным коэффициентам. Конечно-элементный расчёт в КОМПАС-3D APM FEM (САПР АСКОН) показывает реальное распределение контактных давлений по линии зуба, концентрацию у переходной поверхности и влияние перекоса валов — это позволяет обоснованно оптимизировать ширину венца и не возить лишний металл [13; 14]."}
]'::jsonb,
'<h2>Введение</h2><p>Зубчатая передача — узел, в котором происходит собственно преобразование крутящего момента и частоты вращения в редукторе. На защите дипломного проекта по машиностроению раздел расчёта зубчатого зацепления показывает государственной экзаменационной комиссии главное: понимает ли автор разницу между <strong>контактной</strong> и <strong>изгибной</strong> прочностью зуба и умеет ли связать выбор материала с реальным ресурсом передачи.</p><p>В этой статье — полный сквозной алгоритм проектирования цилиндрической зубчатой передачи: выбор сталей и термообработки колёс, определение допускаемых напряжений, проектный расчёт межосевого расстояния и модуля, проверка по контактной и изгибной выносливости по <strong>ГОСТ 21354-87</strong> и финальная конечно-элементная проверка в отечественной САПР <strong>КОМПАС-3D APM FEM</strong>. Только формулы, ГОСТы, марки сталей и числовые ориентиры.</p><p>Способность посчитать передачу точно, а не «с тройным запасом из методички» — это и есть основа технологического суверенитета: отечественный редуктор выигрывает в массе и КПД ровно настолько, насколько грамотно его конструктор распорядился прочностью материала.</p>\n\n<h2>1. Исходные данные</h2><p>Расчёт передачи ведётся после кинематического расчёта привода. На входе известны: передаваемая мощность <em>P</em>, кВт; частоты вращения шестерни <em>n<sub>1</sub></em> и колеса <em>n<sub>2</sub></em>, об/мин; передаточное число <em>u</em> = n<sub>1</sub>/n<sub>2</sub>; крутящий момент на колесе <em>T<sub>2</sub></em> = 9550·P·η / n<sub>2</sub>, Н·м; требуемый ресурс <em>L<sub>h</sub></em>, часов; характер нагрузки (постоянная, переменная, реверсивная).</p>\n\n<h2>2. Выбор материала и термообработки колёс</h2><p>Для редукторов общего назначения применяют термоулучшаемые и цементируемые конструкционные стали. Шестерню, как более нагруженную деталь (за оборот её зуб входит в зацепление в <em>u</em> раз чаще зуба колеса), назначают твёрже колеса на 20…30 HB.</p><ul><li><strong>Сталь 45 (ГОСТ 1050-2013), улучшение</strong> до 235…262 HB — σ<sub>в</sub> = 780 МПа. Для тихоходных малонагруженных передач.</li><li><strong>Сталь 40Х (ГОСТ 4543-2016), улучшение</strong> до 269…302 HB — σ<sub>в</sub> = 900…1000 МПа. Базовый выбор для средненагруженных редукторов.</li><li><strong>Сталь 20Х, 18ХГТ, цементация и закалка</strong> до HRC 56…62 — для тяжелонагруженных быстроходных ступеней. Несущая способность по контакту возрастает в 2…3 раза.</li></ul><p>Термообработка определяет предел контактной выносливости σ<sub>H lim b</sub> и, следовательно, габариты передачи [2, т. 3; 5, с. 49].</p>\n\n<h2>3. Допускаемые напряжения</h2><h3>3.1. Контактные</h3><p>[σ<sub>H</sub>] = σ<sub>H lim b</sub> · K<sub>HL</sub> / S<sub>H</sub>. Для улучшенных сталей σ<sub>H lim b</sub> = 2·HB + 70 МПа; коэффициент запаса S<sub>H</sub> = 1,1 для нормализованных и улучшенных, 1,2 — для поверхностно упрочнённых колёс. Коэффициент долговечности K<sub>HL</sub> = ∜(N<sub>HO</sub>/N<sub>HE</sub>), но не более 2,6, где N<sub>HO</sub> — базовое, N<sub>HE</sub> — эквивалентное число циклов [1, с. 33].</p><p>Для косозубой передачи в качестве расчётного принимают [σ<sub>H</sub>] = 0,45·([σ<sub>H1</sub>] + [σ<sub>H2</sub>]), но не более 1,23·[σ<sub>H2</sub>] (по менее прочному колесу).</p><h3>3.2. Изгибные</h3><p>[σ<sub>F</sub>] = σ<sub>F lim b</sub> · K<sub>FL</sub> / S<sub>F</sub>, где σ<sub>F lim b</sub> = 1,8·HB для улучшенных сталей, S<sub>F</sub> = 1,7…2,2, коэффициент долговечности K<sub>FL</sub> = ⁶√(N<sub>FO</sub>/N<sub>FE</sub>) [1, с. 44].</p>\n\n<h2>4. Проектный расчёт межосевого расстояния</h2><p>Габарит передачи задаёт межосевое расстояние, определяемое из условия контактной выносливости:</p><p style="text-align:center"><strong>a<sub>w</sub> = K<sub>a</sub>·(u + 1)·∛( T<sub>2</sub>·K<sub>Hβ</sub> / (ψ<sub>ba</sub>·u²·[σ<sub>H</sub>]²) )</strong></p><p>где K<sub>a</sub> = 43 для косозубых и 49,5 для прямозубых передач; ψ<sub>ba</sub> = b/a<sub>w</sub> — коэффициент ширины венца (0,25…0,4 для симметричного расположения колёс относительно опор); K<sub>Hβ</sub> — коэффициент неравномерности распределения нагрузки по ширине (1,0…1,15). Полученное значение округляют до стандартного ряда по ГОСТ 2185-66 [3, с. 36].</p>\n\n<h2>5. Модуль, число зубьев и геометрия</h2><p>Модуль назначают m = (0,01…0,02)·a<sub>w</sub> с округлением до стандартного по ГОСТ 9563-60. Суммарное число зубьев косозубой передачи z<sub>Σ</sub> = 2·a<sub>w</sub>·cos β / m, где угол наклона β = 8…16°. Число зубьев шестерни z<sub>1</sub> = z<sub>Σ</sub>/(u+1), но не менее z<sub>min</sub> = 17·cos³β во избежание подрезания. Число зубьев колеса z<sub>2</sub> = z<sub>Σ</sub> − z<sub>1</sub>. После уточняют фактическое u и угол β из условия точного a<sub>w</sub> [3, с. 38].</p>\n\n<h2>6. Проверочный расчёт по контактным напряжениям</h2><p>Действующее контактное напряжение:</p><p style="text-align:center"><strong>σ<sub>H</sub> = Z<sub>H</sub>·Z<sub>M</sub>·Z<sub>ε</sub>·√( F<sub>t</sub>·K<sub>H</sub>·(u+1) / (b·d<sub>1</sub>·u) ) ≤ [σ<sub>H</sub>]</strong></p><p>где Z<sub>H</sub> — коэффициент формы сопряжённых поверхностей, Z<sub>M</sub> = 275 (МПа)<sup>0,5</sup> — коэффициент механических свойств для стальных колёс, Z<sub>ε</sub> — коэффициент торцевого перекрытия, F<sub>t</sub> = 2·T<sub>1</sub>/d<sub>1</sub> — окружная сила, K<sub>H</sub> = K<sub>Hβ</sub>·K<sub>Hv</sub> — суммарный коэффициент нагрузки. Допускается недогрузка до 10 % и перегрузка до 5 % [1, с. 31; ГОСТ 21354-87].</p>\n\n<h2>7. Проверочный расчёт по изгибной выносливости</h2><p>Напряжение у основания зуба:</p><p style="text-align:center"><strong>σ<sub>F</sub> = (F<sub>t</sub>·K<sub>F</sub>·Y<sub>F</sub>·Y<sub>β</sub>·Y<sub>ε</sub>) / (b·m) ≤ [σ<sub>F</sub>]</strong></p><p>где Y<sub>F</sub> — коэффициент формы зуба (для z = 20 Y<sub>F</sub> ≈ 4,07; для z = 100 Y<sub>F</sub> ≈ 3,60), Y<sub>β</sub> = 1 − β/140 — коэффициент наклона зуба, Y<sub>ε</sub> — коэффициент перекрытия, K<sub>F</sub> = K<sub>Fβ</sub>·K<sub>Fv</sub>. Расчёт ведут отдельно для шестерни и колеса; разрушающим считается зуб с меньшим отношением [σ<sub>F</sub>]/Y<sub>F</sub> [1, с. 44; 5, с. 58].</p>\n\n<h2>8. Конечно-элементная проверка в КОМПАС APM FEM</h2><p>Классическая методика ГОСТ 21354-87 оперирует справочными коэффициентами и даёт усреднённую картину. Конечно-элементный расчёт в отечественной САПР <strong>КОМПАС-3D с модулем APM FEM</strong> позволяет:</p><ul><li>построить эпюру контактных давлений вдоль линии зуба и увидеть концентрацию при перекосе валов;</li><li>оценить напряжения у переходной (галтельной) поверхности зуба, где зарождается усталостная трещина;</li><li>проверить влияние модификации профиля (фланкирование, бочкообразность) на пятно контакта;</li><li>обоснованно уменьшить ширину венца b и снизить массу редуктора без потери ресурса [13; 14].</li></ul><p>Именно связка «классический расчёт по ГОСТ → верификация КЭ в российском ПО» отличает дипломника-инженера от компилятора чужих чертежей.</p>\n\n<h2>Заключение</h2><p>Грамотный расчёт зубчатой передачи строится на двух независимых критериях: контактной выносливости рабочих поверхностей (определяет габарит и межосевое расстояние) и изгибной выносливости зуба (определяет модуль). Выбор материала и термообработки задаёт допускаемые напряжения и, в конечном счёте, массу редуктора. Проверка в КОМПАС APM FEM превращает раздел ВКР из формального пересчёта по методичке в полноценное инженерное обоснование конструкции — именно это поднимает уровень отечественной инженерии.</p>',
'[
